# TableOfContents

**File:** `app/components/TableOfContents.tsx`

## Purpose
Sidebar-friendly article navigation for `h2` sections. Flat `h3` items are grouped beneath their preceding `h2` internally, but only primary `h2` anchors are rendered. Labels have emoji removed before display.

Automatically injected by `ArticleEnhancer` into `ArticleTocPlaceholder`; it is not normally authored in article content.

## Props

| Prop | Type | Default | Description |
|---|---|---|---|
| `items` | `TocItem[]` | Required | Heading items, including flat or nested `h3` items. |
| `title` | `string` | `"Contents"` | Visible TOC heading. |
| `ariaLabel` | `string` | `"Table of contents"` | Accessible navigation label. |
| `className` | `string` | — | Additional container classes. |
| `activeId` | `string` | — | Controlled active section ID. |
| `onItemClick` | `(id: string) => void` | — | Called after selecting a section. |

```tsx
"use client";

import { useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router";

export type TocItem = {
    id: string;
    label: string;
    level: 2 | 3;
    children?: TocItem[];
};

type TableOfContentsProps = {
    items: TocItem[];
    title?: string;
    ariaLabel?: string;
    className?: string;
    activeId?: string;
    onItemClick?: (id: string) => void;
};

const EMOJI_RE = /[\p{Extended_Pictographic}\uFE0F]/gu;

function groupItems(items: TocItem[]): TocItem[] {
    const grouped: TocItem[] = [];
    let parent: TocItem | undefined;

    for (const item of items) {
        if (item.level === 2) {
            parent = { ...item, children: [...(item.children ?? [])] };
            grouped.push(parent);
        } else if (parent) {
            parent.children?.push(item);
        }
    }

    return grouped;
}

function cleanLabel(label: string): string {
    return label.replace(EMOJI_RE, "").replace(/\s+/g, " ").trim();
}

export function TableOfContents({
    items,
    title = "Contents",
    ariaLabel = "Table of contents",
    className,
    activeId,
    onItemClick,
}: TableOfContentsProps): JSX.Element {
    const navigate = useNavigate();
    const primaryItems = useMemo(() => groupItems(items), [items]);
    const [observedId, setObservedId] = useState<string>();
    const currentId = activeId ?? observedId;
    const primaryIds = primaryItems.map((item) => item.id).join("|");
    const currentItem = primaryItems.find((item) => item.id === currentId);

    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                const visible = entries.find((entry) => entry.isIntersecting);
                if (visible) setObservedId(visible.target.id);
            },
            { rootMargin: "-15% 0px -70% 0px" },
        );

        for (const item of primaryItems) {
            const heading = document.getElementById(item.id);
            if (heading) observer.observe(heading);
        }

        return () => observer.disconnect();

