    slug,
    ctaText = "Read more",
    className,
    descriptionOverride,
    variant = "default",
    authorOverride,
}: ArticleCardBySlugProps): JSX.Element | null {
    const article = articles.find((item) => item.slug === slug);

    if (!article) {
